@flower.code:
local pts = {}
local total = params.petals * 2
for i = 0, total - 1 do
  local angle = (i / total) * 2 * math.pi
  local r = (i % 2 == 0) and params.outerRadius or params.innerRadius
  pts[#pts + 1] = { r * math.cos(angle), r * math.sin(angle) }
end
return geo.polygon({ points = pts })
